1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	function calculateQuotePremium(items: any[]): number {
14	  const totalBasePremium = items.reduce(
15	    (sum: number, item: any) => sum + (BASE_PREMIUM[item.type] ?? 0),
16	    0,
17	  );
18	
19	  const firstInsurance = totalBasePremium * FIRST_INSURANCE_RATE;
20	  return Math.ceil(totalBasePremium + firstInsurance + PROCESSING_FEE);
21	}
22	
23	export function processScenario(scenario: any): unknown {
24	  const results = scenario.steps.map((step: any) => ({
25	    premium: calculateQuotePremium(step.items),
26	  }));
27	
28	  return { results };
29	}
